import { ref, inject, provide, getCurrentScope, onScopeDispose, type InjectionKey, type Ref } from 'vue'
import { isClient } from '@/lib/env'
import { MAX_TOASTS } from '@/lib/defaults'
import type { VariantProps } from 'class-variance-authority'
import { toastVariants } from '@/components/ui/toast/toast-variants'

type ToastVariantProps = VariantProps<typeof toastVariants>

export interface ToastItem {
    id: string
    variant?: NonNullable<ToastVariantProps['variant']>
    size?: NonNullable<ToastVariantProps['size']>
    title?: string
    description?: string
    duration?: number
}

export interface ToastStackOptions {
    maxVisible?: number
    gap?: number
    expandDirection?: 'down' | 'up'
}

export type ToastPosition =
    | 'top-left'
    | 'top-center'
    | 'top-right'
    | 'bottom-left'
    | 'bottom-center'
    | 'bottom-right'
    | { x: number; y: number; anchor?: 'top-left' | 'bottom-left' | 'top-right' | 'bottom-right' }

export interface PromiseToastOptions<T> {
    loading: string
    success: string | ((data: T) => string)
    error: string | ((error: Error) => string)
    duration?: number
    loadingVariant?: NonNullable<ToastVariantProps['variant']>
    successVariant?: NonNullable<ToastVariantProps['variant']>
    errorVariant?: NonNullable<ToastVariantProps['variant']>
}

export interface UseToastReturn {
    toasts: Ref<ToastItem[]>
    addToast: (toast: Omit<ToastItem, 'id'>) => string
    removeToast: (id: string) => void
    clearToasts: () => void
    clearAllTimers: () => void
    success: (title: string, description?: string) => string
    error: (title: string, description?: string) => string
    warning: (title: string, description?: string) => string
    info: (title: string, description?: string) => string
    promise: <T>(promiseOrFn: Promise<T> | (() => Promise<T>), options: PromiseToastOptions<T>) => Promise<T>
}

const TOAST_KEY: InjectionKey<UseToastReturn> = Symbol('brutx-toast')
export const DEFAULT_TOAST_DURATION = 5000

export function createToast(isFallback = false): UseToastReturn {
    const toasts = ref<ToastItem[]>([])
    const timerMap = new Map<string, ReturnType<typeof setTimeout>>()

    function clearTimer(id: string) {
        const timerId = timerMap.get(id)
        if (timerId !== undefined) {
            clearTimeout(timerId)
            timerMap.delete(id)
        }
    }

    function addToast(toast: Omit<ToastItem, 'id'>) {
        const id = `toast-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`
        if (toasts.value.length >= MAX_TOASTS) {
            const removed = toasts.value[0]
            if (removed) {
                clearTimer(removed.id)
            }
            toasts.value = toasts.value.slice(1)
        }
        toasts.value = [...toasts.value, { ...toast, id }]
        const duration = toast.duration ?? DEFAULT_TOAST_DURATION
        if (duration > 0 && isClient) {
            const timerId = window.setTimeout(() => removeToast(id), duration)
            timerMap.set(id, timerId)
        }
        return id
    }

    function removeToast(id: string) {
        clearTimer(id)
        toasts.value = toasts.value.filter((t) => t.id !== id)
    }

    function clearAllTimers() {
        timerMap.forEach((timerId) => clearTimeout(timerId))
        timerMap.clear()
    }

    function clearToasts() {
        clearAllTimers()
        toasts.value = []
    }

    if (!isFallback && getCurrentScope()) {
        onScopeDispose(() => {
            clearToasts()
        })
    }

    function success(title: string, description?: string) {
        return addToast({ variant: 'success', title, description })
    }

    function error(title: string, description?: string) {
        return addToast({ variant: 'error', title, description })
    }

    function warning(title: string, description?: string) {
        return addToast({ variant: 'warning', title, description })
    }

    function info(title: string, description?: string) {
        return addToast({ variant: 'info', title, description })
    }

    async function promise<T>(
        promiseOrFn: Promise<T> | (() => Promise<T>),
        options: PromiseToastOptions<T>
    ): Promise<T> {
        const promiseValue = typeof promiseOrFn === 'function' ? promiseOrFn() : promiseOrFn
        const loadingId = addToast({
            variant: options.loadingVariant ?? 'default',
            title: options.loading,
            duration: 0,
        })

        try {
            const data = await promiseValue
            removeToast(loadingId)
            const successMessage = typeof options.success === 'function'
                ? options.success(data)
                : options.success
            addToast({
                variant: options.successVariant ?? 'success',
                title: successMessage,
                duration: options.duration,
            })
            return data
        } catch (err) {
            removeToast(loadingId)
            const errorObj = err instanceof Error ? err : new Error(String(err))
            const errorMessage = typeof options.error === 'function'
                ? options.error(errorObj)
                : options.error
            addToast({
                variant: options.errorVariant ?? 'error',
                title: errorMessage,
                duration: options.duration,
            })
            throw err
        }
    }

    return {
        toasts,
        addToast,
        removeToast,
        clearToasts,
        clearAllTimers,
        success,
        error,
        warning,
        info,
        promise,
    }
}

let fallbackInstance: UseToastReturn | null = null

function destroyFallback() {
    if (fallbackInstance) {
        fallbackInstance.clearAllTimers()
        fallbackInstance = null
    }
}

export function provideToast(): UseToastReturn {
    const toast = createToast()
    provide(TOAST_KEY, toast)
    return toast
}

export function useToast(): UseToastReturn {
    const toast = inject(TOAST_KEY)
    if (toast) return toast
    if (typeof console !== 'undefined') {
        console.warn('[BrutxUI] useToast() called without provideToast(). Falling back to shared singleton. Call provideToast() in your root component.')
    }
    if (!fallbackInstance) {
        fallbackInstance = createToast(true)
    }
    return fallbackInstance
}

export { destroyFallback }

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

